     1→// ============================================================================
     2→// REAL-TIME TOOL STATE MANAGEMENT
     3→// Tracks the state of tools being built by Maestri in real-time
     4→// Supports resumable tool creation and state persistence
     5→// ============================================================================
     6→
     7→import { logger } from '@/lib/logger';
     8→import type { ToolType } from './tool-events';
     9→
    10→// Tool creation status
    11→export type ToolStatus =
    12→  | 'initializing'   // Tool just started
    13→  | 'building'       // Actively being built
    14→  | 'paused'         // Temporarily paused
    15→  | 'completed'      // Successfully finished
    16→  | 'error'          // Failed with error
    17→  | 'cancelled';     // User cancelled
    18→
    19→// Base content types for different tools
    20→export interface MindmapContent {
    21→  centralTopic: string;
    22→  nodes: Array<{
    23→    id: string;
    24→    label: string;
    25→    parentId: string | null;
    26→    color?: string;
    27→  }>;
    28→}
    29→
    30→export interface FlashcardContent {
    31→  cards: Array<{
    32→    id: string;
    33→    front: string;
    34→    back: string;
    35→    hint?: string;
    36→  }>;
    37→}
    38→
    39→export interface QuizContent {
    40→  questions: Array<{
    41→    id: string;
    42→    question: string;
    43→    options: string[];
    44→    correctIndex: number;
    45→    explanation?: string;
    46→  }>;
    47→}
    48→
    49→export interface SummaryContent {
    50→  sections: Array<{
    51→    id: string;
    52→    heading: string;
    53→    content: string;
    54→  }>;
    55→}
    56→
    57→export interface TimelineContent {
    58→  events: Array<{
    59→    id: string;
    60→    date: string;
    61→    title: string;
    62→    description: string;
    63→  }>;
    64→}
    65→
    66→export interface DiagramContent {
    67→  type: 'flowchart' | 'sequence' | 'class' | 'er';
    68→  mermaidCode: string;
    69→}
    70→
    71→// Union type for all tool content
    72→export type ToolContent =
    73→  | MindmapContent
    74→  | FlashcardContent
    75→  | QuizContent
    76→  | SummaryContent
    77→  | TimelineContent
    78→  | DiagramContent;
    79→
    80→// Tool state structure
    81→export interface ToolState {
    82→  id: string;
    83→  type: ToolType;
    84→  status: ToolStatus;
    85→  sessionId: string;
    86→  maestroId: string;
    87→
    88→  // Metadata
    89→  title: string;
    90→  subject?: string;
    91→  createdAt: number;
    92→  updatedAt: number;
    93→
    94→  // Progress tracking
    95→  progress: number; // 0-100
    96→  chunksReceived: number;
    97→
    98→  // Content (incrementally built)
    99→  content: Partial<ToolContent>;
   100→
   101→  // Raw chunks for replay/debugging
   102→  rawChunks: string[];
   103→
   104→  // Error info if failed
   105→  errorMessage?: string;
   106→}
   107→
   108→// In-memory store for active tool states
   109→// Key: toolId, Value: ToolState
   110→const activeTools = new Map<string, ToolState>();
   111→
   112→// Session to tools mapping for quick lookup
   113→const sessionTools = new Map<string, Set<string>>();
